﻿// ============================================================
// 个人云数据存储 - Cloudflare Worker
// 配置驱动架构 —— 新增分类只需在 CATEGORIES 加一行
// ============================================================
import { HTML } from './html.js';

const CATEGORIES = ["images", "novels", "documents", "stickies"];

function json(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' }
  });
}

function error(msg, status = 400) {
  return json({ error: msg }, status);
}

function corsHeaders() {
  return {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'GET,POST,PUT,DELETE,OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type'
  };
}

function generateId() {
  return Date.now().toString(36) + Math.random().toString(36).substring(2, 10);
}

async function listItems(env, category) {
  const prefix = category ? 'item:' + category + ':' : 'item:';
  const result = await env.PERSONAL_CLOUD_KV.list({ prefix });
  const items = [];
  for (const key of result.keys) {
    const val = await env.PERSONAL_CLOUD_KV.get(key.name, 'json');
    if (val) items.push(val);
  }
  items.sort((a, b) => new Date(b.updatedAt) - new Date(a.updatedAt));
  return items;
}

async function getCounts(env) {
  const all = await env.PERSONAL_CLOUD_KV.list({ prefix: 'item:' });
  const counts = { all: 0 };
  CATEGORIES.forEach(c => counts[c] = 0);
  for (const key of all.keys) {
    counts.all++;
    const parts = key.name.split(':');
    if (parts.length >= 2) {
      const cat = parts[1];
      if (counts[cat] !== undefined) counts[cat]++;
    }
  }
  return counts;
}

async function findItem(env, itemId) {
  for (const cat of CATEGORIES) {
    const item = await env.PERSONAL_CLOUD_KV.get('item:' + cat + ':' + itemId, 'json');
    if (item) return { item, key: 'item:' + cat + ':' + itemId };
  }
  return null;
}

export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const path = url.pathname;

    if (request.method === 'OPTIONS') {
      return new Response(null, { status: 204, headers: corsHeaders() });
    }

    // Serve frontend
    if (path === '/' || path === '/index.html') {
      return new Response(HTML, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' }
      });
    }

    // API: list / counts
    if (path === '/api/items' || path === '/api/items/') {
      if (request.method === 'GET') {
        if (url.searchParams.has('counts')) {
          const counts = await getCounts(env);
          return json(counts);
        }
        const category = url.searchParams.get('category') || null;
        const items = await listItems(env, category);
        return json(items);
      }

      if (request.method === 'POST') {
        try {
          const body = await request.json();
          if (!body.title || !body.category) return error('标题和分类为必填项');
          if (!CATEGORIES.includes(body.category)) return error('无效的分类');
          const id = generateId();
          const now = new Date().toISOString();
          const item = {
            id,
            title: body.title,
            content: body.content || '',
            category: body.category,
            fileData: body.fileData || null,
            fileName: body.fileName || null,
            fileType: body.fileType || null,
            fileSize: body.fileSize || 0,
            createdAt: now,
            updatedAt: now
          };
          await env.PERSONAL_CLOUD_KV.put('item:' + item.category + ':' + id, JSON.stringify(item));
          return json(item, 201);
        } catch (e) {
          return error('请求格式错误: ' + e.message);
        }
      }
    }

    // API: item by ID
    const match = path.match(/^\/api\/items\/([a-z0-9]+)$/);
    if (match) {
      const itemId = match[1];

      if (request.method === 'GET') {
        const found = await findItem(env, itemId);
        if (!found) return error('未找到', 404);
        return json(found.item);
      }

      if (request.method === 'PUT') {
        try {
          const body = await request.json();
          const found = await findItem(env, itemId);
          if (!found) return error('未找到', 404);

          const existing = found.item;
          const newCategory = (body.category && CATEGORIES.includes(body.category)) ? body.category : existing.category;
          const updated = {
            ...existing,
            title: body.title !== undefined ? body.title : existing.title,
            content: body.content !== undefined ? body.content : existing.content,
            category: newCategory,
            fileData: body.fileData !== undefined ? body.fileData : existing.fileData,
            fileName: body.fileName !== undefined ? body.fileName : existing.fileName,
            fileType: body.fileType !== undefined ? body.fileType : existing.fileType,
            fileSize: body.fileSize !== undefined ? body.fileSize : existing.fileSize,
            updatedAt: new Date().toISOString()
          };

          const newKey = 'item:' + newCategory + ':' + itemId;
          if (found.key !== newKey) {
            await env.PERSONAL_CLOUD_KV.delete(found.key);
          }
          await env.PERSONAL_CLOUD_KV.put(newKey, JSON.stringify(updated));
          return json(updated);
        } catch (e) {
          return error('请求格式错误: ' + e.message);
        }
      }

      if (request.method === 'DELETE') {
        const found = await findItem(env, itemId);
        if (!found) return error('未找到', 404);
        await env.PERSONAL_CLOUD_KV.delete(found.key);
        return json({ success: true });
      }
    }

    return error('Not Found', 404);
  }
};
